CREATE FUNCTION find_first_zero_quantity_product() RETURNS INT AS $$
DECLARE
    counter INT := 1; 
    c_quantity INT;
    max_id INT;
BEGIN
    SELECT MAX(product_id) INTO max_id FROM products;

    LOOP
        SELECT quantity INTO c_quantity FROM products WHERE product_id = counter;

        IF c_quantity = 0 THEN
            RETURN counter;
        END IF;

        counter := counter + 1;

        IF counter > max_id THEN
            RETURN NULL;
        END IF;
    END LOOP;
END;
$$ LANGUAGE plpgsql;

